const filteredData = $derived.by(() => {
	if (!value?.start || !value?.end) return chartData;
	return chartData.filter(({ date }) => {
		const dateObj = new Date(date);
		if (!value) return true;
		const startDate = value.start!.toDate(getLocalTimeZone());
		const endDate = value.end!.toDate(getLocalTimeZone());
		// set end date to end of day to include the full day
		endDate.setHours(23, 59, 59, 999);
		return dateObj >= startDate && dateObj <= endDate;
	});
});

export const load: PageLoad = async ({ params, fetch }) => {
	const doc = await getDoc(params.slug);
	const name = doc.metadata.slug;
	if (params.slug.includes("components/") && !ITEMS_TO_IGNORE.includes(name)) {
		const res = await fetch(`/api/block/${name}`);
		const item: HighlightedBlock = await res.json();

		return { ...doc, viewerData: item };
	}

	return { ...doc, viewerData: null };
};

if (parsed.metadata.ts) {
	parsed = {
		...parsed,
		fragment: parsed.fragment && remove_typescript_nodes(parsed.fragment),
		instance: parsed.instance && remove_typescript_nodes(parsed.instance),
		module: parsed.module && remove_typescript_nodes(parsed.module)
	};
	if (combined_options.customElementOptions?.extend) {
		combined_options.customElementOptions.extend = remove_typescript_nodes(
			combined_options.customElementOptions?.extend
		);
	}
}

if (options_index !== -1) {
	const options = /** @type {AST.SvelteOptionsRaw} */ (this.root.fragment.nodes[options_index]);
	this.root.fragment.nodes.splice(options_index, 1);
	this.root.options = read_options(options);

	disallow_children(options);

	// We need this for the old AST format
	Object.defineProperty(this.root.options, '__raw__', {
		value: options,
		enumerable: false
	});
}

const registryTheme = $derived.by(() => {
	if (!designSystem.baseColor || !designSystem.theme || !designSystem.menuAccent || !radius) {
		return null;
	}

	const config: DesignSystemConfig = {
		...DEFAULT_CONFIG,
		baseColor: designSystem.baseColor,
		theme: designSystem.theme,
		chartColor: designSystem.chartColor ?? DEFAULT_CONFIG.chartColor,
		menuAccent: designSystem.menuAccent,
		radius: effectiveRadius,
	};

	return buildRegistryTheme(config);
});

const currentPreset = $derived(
	PRESETS.find(
		(preset) =>
			preset.baseColor === designSystem.baseColor &&
			preset.style === designSystem.style &&
			preset.theme === designSystem.theme &&
			preset.iconLibrary === designSystem.iconLibrary &&
			preset.font === designSystem.font &&
			preset.menuAccent === designSystem.menuAccent &&
			preset.menuColor === designSystem.menuColor &&
			preset.radius === designSystem.radius
	)
);

// Set up all routes
const routesList: RouteItem[] = []
// svelte-ignore state_referenced_locally
// routes are static, initial capture is intended
if (routes instanceof Map) {
    routes.forEach((route, path) => {
        routesList.push(new RouteItem(path, route))
    })
}
else {
    Object.keys(routes).forEach((path) => {
        const map = routes as Record<string, Component<any, any> | WrappedComponent>
        routesList.push(new RouteItem(path, map[path]))
    })
}

return async (icon: string) => {
	const preloadedIcon = preloadedIcons.get(icon);
	if (preloadedIcon !== undefined) return preloadedIcon;

	let mod: Record<string, Component>;
	try {
		mod = await import(`$lib/registry/icons/__${iconLibrary}__/${icon}.ts`);
	} catch {
		preloadedIcons.set(icon, null);
		return null;
	}
	const Icon = mod[icon];
	preloadedIcons.set(icon, Icon);

	return Icon;
};

if (!agent && prompt) {
	const options: Options = AGENT_NAMES.map((pm) => ({ value: pm, label: pm }));
	options.unshift({ label: "None", value: undefined });

	const userAgent = getUserAgent() ?? undefined; // replaces `null` for `undefined`
	const pm = await p.select({
		options,
		initialValue: userAgent,
		message: "Which package manager do you want to use?",
	});
	if (p.isCancel(pm)) {
		cancel();
	}

	return pm;
}

buttonProps = {
  role: "button",
  "aria-haspopup": "true",
  id: hideIcon ? triggerId : undefined,
  class: hideIcon ? "bx--tooltip__label" : "bx--tooltip__trigger",
  "aria-expanded": open,
  "aria-describedby": open ? tooltipId : undefined,
  "aria-labelledby": triggerText ? triggerId : undefined,
  "aria-label": triggerText ? undefined : iconDescription,
  tabindex,
  style: hideIcon ? $$restProps.style : undefined,
};

return {
		name: role === "body" ? `font-${definition.name}` : `font-heading-${definition.name}`,
		title: role === "body" ? definition.title : `${definition.title} (Heading)`,
		type: "registry:font",
		font: {
			family: definition.family,
			provider: definition.provider,
			variable: role === "body" ? definition.registryVariable : "--font-heading",
			...(definition.weight ? { weight: [...definition.weight] } : {}),
			subsets: [...definition.subsets],
			import: definition.import,
			dependency: definition.dependency,
		},
	} satisfies RegistryItem;

{#if typeof content === "string"}
	{content}
{:else if content instanceof Function}
	<!-- It's unlikely that a CellContext will be passed to a Header -->
	<!-- eslint-disable-next-line @typescript-eslint/no-explicit-any -->
	{@const result = content(context as any)}
	{#if result instanceof RenderComponentConfig}
		{@const { component: Component, props } = result}
		<Component {...props} {attach} />
	{:else if result instanceof RenderSnippetConfig}
		{@const { snippet, params } = result}
		{@render snippet({ ...params, attach })}
	{:else}
		{result}
	{/if}
{/if}

const CONTINUATION_OPTIONS = {
	presets: {
		label: "Choose from a list of pre-configured presets",
		select: (existingConfig) => presets(existingConfig),
	},
	customize: {
		label: `Create my own preset at ${color.bold("shadcn-svelte.com/create")}`,
		select: (existingConfig) => customize(existingConfig),
	},
	prompt: {
		label: "Prompt me for the preset",
		select: (existingConfig) => prompt(existingConfig),
	},
} as const satisfies Record<string, ContinuationOption>;

if (selectedId === undefined) {
  prevSelectedId = selectedId;
  selectedItem = undefined;
} else {
  if (prevSelectedId !== selectedId) {
    // Only dispatch select event if not initial render (prevSelectedId was not null)
    const isInitialRender = prevSelectedId === null;
    prevSelectedId = selectedId;
    selectedItem = itemsById.get(selectedId);
    if (!isInitialRender) {
      dispatch("select", { selectedId, selectedItem });
    }
  }
}

const inputGroupButtonVariants = tv({
	base: "cn-input-group-button flex items-center shadow-none",
	variants: {
		size: {
			xs: "cn-input-group-button-size-xs",
			sm: "cn-input-group-button-size-sm",
			"icon-xs": "cn-input-group-button-size-icon-xs",
			"icon-sm": "cn-input-group-button-size-icon-sm",
		},
	},
	defaultVariants: {
		size: "xs",
	},
});

if (root.options) {
	for (const attribute of root.options.attributes) {
		if (attribute.name === 'accessors' && analysis.runes) {
			w.options_deprecated_accessors(attribute);
		}

		if (attribute.name === 'customElement' && !custom_element_from_option) {
			w.options_missing_custom_element(attribute);
		}

		if (attribute.name === 'immutable' && analysis.runes) {
			w.options_deprecated_immutable(attribute);
		}
	}
}

for (const node of analysis.module.ast.body) {
	if (node.type === 'ExportNamedDeclaration' && node.specifiers !== null && node.source == null) {
		for (const specifier of node.specifiers) {
			if (specifier.local.type !== 'Identifier') continue;
			const name = specifier.local.name;
			const binding = analysis.module.scope.get(name);
			if (!binding) {
				if ([...analysis.snippets].find((snippet) => snippet.expression.name === name)) {
					e.snippet_invalid_export(specifier);
				} else {
					e.export_undefined(specifier, name);
				}
			}
		}
	}
}

if (constructor) {
	for (const statement of constructor.value.body.body) {
		if (statement.type !== 'ExpressionStatement') continue;
		if (statement.expression.type !== 'AssignmentExpression') continue;

		const { left, right } = statement.expression;

		if (left.type !== 'MemberExpression') continue;
		if (left.object.type !== 'ThisExpression') continue;
		if (left.computed && left.property.type !== 'Literal') continue;

		handle(statement.expression, left.property, right);
	}
}

for (const attribute of node.attributes) {
	if (attribute.type !== 'Attribute' || !valid.includes(attribute.name)) {
		e.svelte_boundary_invalid_attribute(attribute);
	}

	if (
		attribute.value === true ||
		(Array.isArray(attribute.value) &&
			(attribute.value.length !== 1 || attribute.value[0].type !== 'ExpressionTag'))
	) {
		e.svelte_boundary_invalid_attribute_value(attribute);
	}
}

if (position === "top-right") {
  notifications = [newNotification, ...notifications];
  if (notifications.length > maxNotifications) {
    notifications.splice(maxNotifications);
  }
} else {
  notifications = [...notifications, newNotification];
  if (notifications.length > maxNotifications) {
    notifications.splice(0, notifications.length - maxNotifications);
  }
}

if (isTailwind3 && isSvelte4) {
	return {
		ok: false,
		error: error(
			`Initializing a project with Tailwind v3 and Svelte v4 is not supported.\n\n` +
				`This CLI version requires Tailwind v4 and Svelte v5 for the ${highlight("init")} command.\n\n` +
				`Please use ${highlight("shadcn-svelte@0.14")} that supports Tailwind v3 + Svelte v4.\n\n`
		),
	};
}

let cleaned_comment_arr = comment
		?.split('\n')
		.map((line) =>
			line
				.trim()
				// replace `// ` for one liners
				.replace(/^\/\/\s*/g, '')
				// replace `\**` for the initial JSDoc
				.replace(/^\/\*\*?\s*/g, '')
				// migrate `*/` for the end of JSDoc
				.replace(/\s*\*\/$/g, '')
				// remove any initial `* ` to clean the comment
				.replace(/^\*\s*/g, '')
		)
		.filter(Boolean);

if (analysis.css.ast !== null && analysis.inject_styles) {
	const hash = b.literal(analysis.css.hash);
	const code = b.literal(render_stylesheet(analysis.source, analysis, options).code);

	state.hoisted.push(b.const('$$css', b.object([b.init('hash', hash), b.init('code', code)])));

	component_block.body.unshift(
		b.stmt(b.call('$.append_styles', b.id('$$anchor'), b.id('$$css')))
	);
}

if (node.metadata.expression.has_blockers() || node.metadata.expression.has_await) {
	context.state.init.push(
		b.stmt(
			b.call(
				'$.async',
				context.state.node,
				node.metadata.expression.blockers(),
				b.array([]), // {#await await ...} is special insofar that the await should not be waited on
				b.arrow([context.state.node], b.block([stmt]))
			)
		)
	);
} else {
	context.state.init.push(stmt);
}

if (isStandalone && radioName) {
  const registration = registerRadioButton(radioName, instanceKey, checked);
  registryStore = registration.selectedKey;
  unregister = registration.unregister;

  // Subscribe to uncheck this radio when a sibling is selected.
  // Only set checked=false when another instance is selected, not checked=true for self.
  // This allows parent components (like DataTable) to control the checked state.
  registryUnsubscribe = registryStore.subscribe((selectedKey) => {
    if (selectedKey !== undefined && selectedKey !== instanceKey) {
      checked = false;
    }
  });

  previousName = radioName;
}

for (const item of itemsWithContent) {
	selectedItems.add(item.name);
	for (const regDep of item.registryDependencies ?? []) {
		selectedItems.add(regDep);
	}

	const itemExists = item.files?.some((file) => {
		const filePath = registry.resolveItemFilePath(opts.config, item, file);
		return existsSync(filePath);
	});
	if (itemExists) {
		existingItems.push(item.name);
	}
}

try {
	const configResult = fs.readFileSync(configPath, { encoding: "utf8" });
	const config = JSON.parse(configResult);
	return parseRawConfig(config);
} catch (e) {
	if (!(e instanceof z.ZodError)) throw e;
	const formatted = z.prettifyError(e);
	throw new ConfigError(
		`Invalid configuration found in ${highlight(configPath)}.\n\n${formatted}`
	);
}

if (typeof config.typescript === "object") {
	const tsconfigPath = path.resolve(cwd, config.typescript.config);
	tsconfigType = path.basename(tsconfigPath);
	tsconfig = getTsconfig(tsconfigPath, tsconfigType);
} else {
	tsconfigType = config.typescript ? "tsconfig.json" : "jsconfig.json";
	tsconfig = getTsconfig(path.resolve(cwd, "package.json"), tsconfigType);
}

for (const font of fonts) {
	// Heading tokens are for `font-heading` / cn-font-heading on components only;
	// body copy stays on `font-sans` (or serif/mono when those are the primary variable).
	if (font.variable === "--font-heading") {
		continue;
	}
	const selector = font.selector ?? "html";
	const cls = font.variable.replace("--", "");
	if (!groups.has(selector)) {
		groups.set(selector, []);
	}
	groups.get(selector)!.push(cls);
}

for (const transformer of transformers.filter(
	(transformer) => transformer !== undefined && transformer !== false
)) {
	const { content, dependencies, devDependencies, filePath } = await transformer({
		config: opts.config,
		content: result.content,
		filePath: result.filePath,
		supportedFontMarkers: opts.supportedFontMarkers,
	});
	result.content = content ?? result.content;
	dependencies?.forEach((dep) => result.dependencies.add(dep));
	devDependencies?.forEach((dep) => result.devDependencies.add(dep));
	result.filePath = filePath ?? result.filePath;
}

return (
	first.type === 'PseudoClassSelector' &&
	first.name === 'global' &&
	(first.args === null ||
		// Only these two selector types keep the whole selector global, because e.g.
		// :global(button).x means that the selector is still scoped because of the .x
		relative_selector.selectors.every(
			(selector) =>
				is_unscoped_pseudo_class(selector) || selector.type === 'PseudoElementSelector'
		))
);

return (
	first.type === 'PseudoClassSelector' &&
	first.name === 'global' &&
	(first.args === null ||
		// Only these two selector types can keep the whole selector global, because e.g.
		// :global(button).x means that the selector is still scoped because of the .x
		relative_selector.selectors.every(
			(selector) =>
				selector.type === 'PseudoClassSelector' || selector.type === 'PseudoElementSelector'
		))
);

const blurInput = (relatedTarget) => {
  if (!calendar) return;
  // No relatedTarget means focus left the document (e.g. switching browser
  // tabs); refocusing would replay the open animation. Outside clicks are
  // handled separately by the window click handler below.
  if (relatedTarget == null) return;
  // In range mode, focus moves between the two inputs while the calendar
  // stays open; closing here would replay the open animation on every switch.
  if (datePickerRef?.contains(/** @type {Node} */ (relatedTarget))) return;
  if (
    calendar.calendarContainer.contains(/** @type {Node} */ (relatedTarget))
  )
    return;
  calendar.close();
};

const formattedCodes = await Promise.all(
  svelteFences.map(async (c) => {
    try {
      const injected = injectImportsIntoSvelteSnippet(c.code);
      const formatted = await prettierFormat(injected, {
        parser: "svelte",
        plugins: [prettierPluginSvelte],
        svelteSortOrder: "scripts-markup-styles-options",
      });
      return String(formatted).trimEnd();
    } catch {
      return null;
    }
  }),
);

if (isTailwind3 && isSvelte5) {
	// no config to update
	if (!config) return config;

	// if no `style` field, then we can assume their components.json is already updated
	if (!config.style) return { ok: true, config };

	config.registry = `${TW3_SITE_BASE_URL}/registry/${config.style}`;
	cliConfig.writeConfig(cwd, config);
	p.log.step(`Config file ${highlight("components.json")} updated`);
	return { ok: true, config };
}

export const registryItemSchema = z.discriminatedUnion("type", [
	registryItemCommonSchema.extend({
		type: z.literal("registry:base"),
		config: naiveDeepPartialify(rawConfigSchema).optional(),
	}),
	registryItemCommonSchema.extend({
		type: z.literal("registry:font"),
		font: registryItemFontSchema,
	}),
	registryItemCommonSchema.extend({
		type: registryItemTypeSchema.exclude(["registry:base", "registry:font"]),
	}),
]);

if (config.menuAccent === "bold") {
	lightVars.accent = lightVars.primary;
	lightVars["accent-foreground"] = lightVars["primary-foreground"];
	darkVars.accent = darkVars.primary;
	darkVars["accent-foreground"] = darkVars["primary-foreground"];
	// lightVars["sidebar-accent"] = lightVars.primary
	// lightVars["sidebar-accent-foreground"] = lightVars["primary-foreground"]
	// darkVars["sidebar-accent"] = darkVars.primary
	// darkVars["sidebar-accent-foreground"] = darkVars["primary-foreground"]
}

import ItemContent from '../anatomy/item-content.svelte';
import ItemIndicator from '../anatomy/item-indicator.svelte';
import ItemTrigger from '../anatomy/item-trigger.svelte';
import Item from '../anatomy/item.svelte';
import RootContext from '../anatomy/root-context.svelte';
import RootProvider from '../anatomy/root-provider.svelte';
import Root from '../anatomy/root.svelte';

export const Accordion = Object.assign(Root, {
	Provider: RootProvider,
	Context: RootContext,
	Item: Item,
	ItemTrigger: ItemTrigger,
	ItemIndicator: ItemIndicator,
	ItemContent: ItemContent,
});
